# Custom sanitization for sensitive data
def sanitize_sensitive_data(data):
    if isinstance(data, dict):
        sanitized = {}
        for key, value in data.items():
            key_lower = key.lower()
            if any(sensitive in key_lower for sensitive in [
                'password', 'token', 'secret', 'api_key', 'auth',
                'credit_card', 'ssn', 'cvv', 'pin'
            ]):
                sanitized[key] = '[REDACTED]'
            elif isinstance(value, (dict, list)):
                sanitized[key] = sanitize_sensitive_data(value)
            else:
                sanitized[key] = value
        return sanitized
    elif isinstance(data, list):
        return [sanitize_sensitive_data(item) for item in data]
    return data

# Decorator to add custom labels and sanitize data
def apm_trace(transaction_name=None, span_type='custom'):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            client = apm.client
            
            # Set custom context with sanitized data
            if request.method in ['POST', 'PUT', 'PATCH']:
                try:
                    request_data = request.get_json(silent=True) or {}
                    sanitized_data = sanitize_sensitive_data(request_data)
                    client.set_custom_context({'request_body': sanitized_data})
                except:
                    pass
            
            # Add user context (sanitized)
            user_id = request.headers.get('X-User-ID')
            if user_id:
                client.set_user_context(
                    user_id=hashlib.sha256(user_id.encode()).hexdigest()[:16],
                    username='[REDACTED]'
                )
            
            # Add custom labels
            client.label(
                endpoint=request.endpoint or 'unknown',
                method=request.method,
                remote_addr=hashlib.sha256(
                    request.remote_addr.encode()
                ).hexdigest()[:16] if request.remote_addr else 'unknown'
            )
            
            result = f(*args, **kwargs)
            return result
        return decorated_function
    return decorator

